     1→/**
     2→ * Dev Bridge RPC Client
     3→ *
     4→ * Provides a unified API that works in both Tauri (native) and browser contexts.
     5→ * In Tauri: Uses native invoke()
     6→ * In Browser: Uses WebSocket connection to dev bridge server
     7→ */
     8→
     9→// Types matching Rust definitions
    10→export interface ProcessInfo {
    11→  id: string;
    12→  cmd: string;
    13→  cwd: string;
    14→  rows: number;
    15→  cols: number;
    16→  running: boolean;
    17→}
    18→
    19→export interface RpcRequest {
    20→  id: string;
    21→  cmd: string;
    22→  args: Record<string, unknown>;
    23→}
    24→
    25→export interface RpcResponse {
    26→  id: string;
    27→  success: boolean;
    28→  result?: unknown;
    29→  error?: string;
    30→}
    31→
    32→export interface RpcEvent {
    33→  event: string;
    34→  payload: unknown;
    35→}
    36→
    37→export interface PtyOutput {
    38→  id: string;
    39→  data: string;
    40→}
    41→
    42→export interface PtyExit {
    43→  id: string;
    44→  code: number | null;
    45→}
    46→
    47→// Check if running in Tauri context
    48→export function isTauri(): boolean {
    49→  return typeof window !== "undefined" && "__TAURI__" in window;
    50→}
    51→
    52→// Dev Bridge connection state
    53→let ws: WebSocket | null = null;
    54→let token: string | null = null;
    55→let pendingRequests: Map<
    56→  string,
    57→  { resolve: (value: unknown) => void; reject: (error: Error) => void }
    58→> = new Map();
    59→let eventHandlers: Map<string, Set<(payload: unknown) => void>> = new Map();
    60→let reconnectAttempts = 0;
    61→const MAX_RECONNECT_ATTEMPTS = 5;
    62→const DEV_BRIDGE_PORT = 9876;
    63→
    64→/**
    65→ * Generate unique request ID
    66→ */
    67→function generateId(): string {
    68→  return `${Date.now()}-${Math.random().toString(36).substring(2, 9)}`;
    69→}
    70→
    71→/**
    72→ * Get token from temp file or environment
    73→ * In development, the Rust server writes token to temp dir
    74→ */
    75→async function getToken(): Promise<string | null> {
    76→  if (token) return token;
    77→
    78→  // Try to fetch token from dev server endpoint
    79→  try {
    80→    const response = await fetch(
    81→      `http://127.0.0.1:${DEV_BRIDGE_PORT}/health`
    82→    );
    83→    if (response.ok) {
    84→      // Token is passed via URL parameter, we need to get it from somewhere
    85→      // For now, try localStorage or prompt
    86→      const storedToken = localStorage.getItem("hq-dev-bridge-token");
    87→      if (storedToken) {
    88→        token = storedToken;
    89→        return token;
    90→      }
    91→    }
    92→  } catch {
    93→    // Server not running
    94→  }
    95→
    96→  return null;
    97→}
    98→
    99→/**
   100→ * Connect to dev bridge WebSocket server
   101→ */
   102→async function connectDevBridge(): Promise<boolean> {
   103→  if (ws && ws.readyState === WebSocket.OPEN) {
   104→    return true;
   105→  }
   106→
   107→  const authToken = await getToken();
   108→  if (!authToken) {
   109→    console.warn(
   110→      "[DevBridge] No token available. Set localStorage 'hq-dev-bridge-token' with the token shown in terminal."
   111→    );
   112→    return false;
   113→  }
   114→
   115→  return new Promise((resolve) => {
   116→    try {
   117→      ws = new WebSocket(
   118→        `ws://127.0.0.1:${DEV_BRIDGE_PORT}/ws?token=${authToken}`
   119→      );
   120→
   121→      ws.onopen = () => {
   122→        console.log("[DevBridge] Connected");
   123→        reconnectAttempts = 0;
   124→        resolve(true);
   125→      };
   126→
   127→      ws.onclose = () => {
   128→        console.log("[DevBridge] Disconnected");
   129→        ws = null;
   130→
   131→        // Reject all pending requests
   132→        pendingRequests.forEach(({ reject }) => {
   133→          reject(new Error("Connection closed"));
   134→        });
   135→        pendingRequests.clear();
   136→
   137→        // Attempt reconnection
   138→        if (reconnectAttempts < MAX_RECONNECT_ATTEMPTS) {
   139→          reconnectAttempts++;
   140→          setTimeout(() => connectDevBridge(), 1000 * reconnectAttempts);
   141→        }
   142→
   143→        resolve(false);
   144→      };
   145→
   146→      ws.onerror = (error) => {
   147→        console.error("[DevBridge] Error:", error);
   148→        resolve(false);
   149→      };
   150→
   151→      ws.onmessage = (event) => {
   152→        try {
   153→          const data = JSON.parse(event.data) as RpcEvent;
   154→
   155→          if (data.event === "rpc-response") {
   156→            const response = data.payload as RpcResponse;
   157→            const pending = pendingRequests.get(response.id);
   158→            if (pending) {
   159→              pendingRequests.delete(response.id);
   160→              if (response.success) {
   161→                pending.resolve(response.result);
   162→              } else {
   163→                pending.reject(new Error(response.error || "Unknown error"));
   164→              }
   165→            }
   166→          } else {
   167→            // Emit event to handlers
   168→            const handlers = eventHandlers.get(data.event);
   169→            if (handlers) {
   170→              handlers.forEach((handler) => handler(data.payload));
   171→            }
   172→
   173→            // Also emit to wildcard handlers
   174→            const wildcardHandlers = eventHandlers.get("*");
   175→            if (wildcardHandlers) {
   176→              wildcardHandlers.forEach((handler) => handler(data));
   177→            }
   178→          }
   179→        } catch (e) {
   180→          console.error("[DevBridge] Failed to parse message:", e);
   181→        }
   182→      };
   183→    } catch (e) {
   184→      console.error("[DevBridge] Failed to connect:", e);
   185→      resolve(false);
   186→    }
   187→  });
   188→}
   189→
   190→/**
   191→ * Check if dev bridge is available
   192→ */
   193→export async function isDevBridgeAvailable(): Promise<boolean> {
   194→  if (isTauri()) return false;
   195→
   196→  try {
   197→    const response = await fetch(
   198→      `http://127.0.0.1:${DEV_BRIDGE_PORT}/health`,
   199→      { signal: AbortSignal.timeout(1000) }
   200→    );
   201→    return response.ok;
   202→  } catch {
   203→    return false;
   204→  }
   205→}
   206→
   207→/**
   208→ * Set the dev bridge token
   209→ */
   210→export function setDevBridgeToken(newToken: string): void {
   211→  token = newToken;
   212→  localStorage.setItem("hq-dev-bridge-token", newToken);
   213→}
   214→
   215→/**
   216→ * Unified invoke function - works in Tauri and browser contexts
   217→ */
   218→export async function invoke<T>(
   219→  cmd: string,
   220→  args: Record<string, unknown> = {}
   221→): Promise<T> {
   222→  // Tauri native context
